AND user_uuid = #{user.user_uuid}
AND ( username LIKE CONCAT('%', #{user.username}, '%') OR email LIKE CONCAT('%', #{user.email}, '%') OR nickname LIKE CONCAT('%', #{user.nickname}, '%') )

SELECT user_id, user_uuid, username, password, nickname, user_role, avatar_url, email, status, is_delete, create_time, update_time FROM tb_user WHERE 1 = 1
AND user_role = #{userRole}
AND status = #{status}
AND is_delete = #{isDelete}
AND is_delete = 0
AND nickname LIKE CONCAT('%', #{nickname}, '%')
ORDER BY create_time ASC
ORDER BY create_time DESC

